INSERT [Log].[ShahkarLog] ([LogId], [NationalId], [MobileNumber], [RequestCode], [IsMatch], [ResponseText], [ExpertId], [CreatedAt], [RequestId]) VALUES (5, N'', N'', N'078520250908102211735164', 1, N'{"isSuccessful":true,"error":0,"errorDescription":"","UsedQuotaStats":{"hourlyUsed":5,"dailyUsed":6,"monthlyUsed":6},"description":"","responseStatusCode":200,"responseText":"{\"result\":{\"data\":{\"RegCases\":[],\"BaseDocuments\":[],\"FollowerDocuments\":[],\"succseed\":true,\"NationalRegisterNo\":\"140432151214000078\",\"DocType\":\"سند وكالت‌نامه\",\"DocType_code\":\"321\",\"HasPermission\":true,\"ExistDoc\":true,\"Desc\":null,\"ScriptoriumName\":\"دفترخانه اسناد رسمي شماره 368 شهر تهران استان تهران\",\"SignGetterTitle\":null,\"SignSubject\":null,\"DocDate\":\"1404/04/22\",\"CaseClasifyNo\":\"44803\",\"ImpotrtantAnnexText\":\"دفترخانه 368 تهران\\nنوع سند: سند وكالت‌نامه\\r\\nتاریخ سند: 1404/04/22\\r\\nشماره سند: 44803\\n--------------------------------------------------\\nوكيل : مهر آذين داتيس\\nموكل : پارسيان تجارت ساتين  با مديريت\\\"آقای محمدرضا فسائي\\\"\\n--------------------------------------------------\\nاین وکالتنامه، بلاعزل نیست.\\nوکیل حق توکیل به غیر ندارد.\\nمهلت اعتبار این وکالتنامه تا تاریخ 1405/04/22 می باشد.\\n--------------------------------------------------\\nمتن سند: \\r\\n1- اخذ اسنادخريد و حمل . 2- اخذ قبض انبار و ترخيصيه و مراجعه به كشتيراني و شركتهاي حمل ونقل جهت اخذ قبض انبار و ارائه چكهاي سپرده .3- تنظيم اظهارنامه . 4- انجام تشريفات گمركي واردات / صادرات / ترانزيت / ورود موقت / مرجوعي / ترخيص كالا . 5- پرداخت حقوق ورودي و عوارض و هزينه هاي گمركي و ماليات هاي متعلقه . 6- اعتراض به تصميمات گمرك و درخواست رد اضافه پرداختي .7- مراجعه به سازمان هاي ذيربط جهت اخذ مجوزهاي مربوطه . 8- درخواست تعيين تعرفه موضوع ماده 43 قانون امورگمركي .9- تقاضاي ارجاع پرونده به كميسيون رسيدگي به اختلافات گمركي . 10- اعتراض به آراء كميسيون هاي بدوي و درخواست ارسال پرونده به كميسيون تجديد نظر .11- حضور دركميسيون هاي بدوي و تجديد نظر رسيدگي به اختلافات گمركي جهت دفاع از پرونده مربوطه .\\rحدود اختيارات :وكيل مرقوم در انجام مورد وكالت بشرح فوق از طرف موكل تام الاختيار بوده اقدام وامضاي مشاراليه بمنزله اقدام و امضاي شخص موكل نافذ و معتبر ميباشد،و مفاد اين ورقه فقط در نفس وكالت موثر است .(حق توكيل بغير ندارد باستثناي كارمند كارگزار )\",\"DocImage\":null,\"DocImage_Base64\":null,\"ADVOCACYENDDATE\":\"1405/04/22\",\"lstFindPersonInQuery\":[{\"NationalNo\":\"10103428549\",\"Birthdate\":null,\"Name\":\"مهر آذين داتيس\",\"Family\":\"\",\"AgentType\":\"\",\"PersonType\":\"حقوقی\",\"PersonType_code\":\"2\",\"NationalNoMovakel\":\"\",\"NameMovakel\":\"\",\"FamilyMovakel\":\"\",\"txtRelation\":null,\"RoleType\":\"وكيل\",\"Person_RoleType_code\":null},{\"NationalNo\":\"14008538831\",\"Birthdate\":null,\"Name\":\"پارسيان تجارت ساتين\",\"Family\":\"\",\"AgentType\":\"\",\"PersonType\":\"حقوقی\",\"PersonType_code\":\"2\",\"NationalNoMovakel\":\"\",\"NameMovakel\":\"\",\"FamilyMovakel\":\"\",\"txtRelation\":null,\"RoleType\":\"موكل\",\"Person_RoleType_code\":null},{\"NationalNo\":\"0021121801\",\"Birthdate\":\"1377/03/03\",\"Name\":\"محمدرضا\",\"Family\":\"فسائي\",\"AgentType\":\"مدير\",\"PersonType\":\"حقیقی\",\"PersonType_code\":\"1\",\"NationalNoMovakel\":\"14008538831\",\"NameMovakel\":\"پارسيان تجارت ساتين\",\"FamilyMovakel\":\"\",\"txtRelation\":\"پارسيان تجارت ساتين  بامديريت محمدرضا فسائي\",\"RoleType\":\"\",\"Person_RoleType_code\":null}]},\"status\":{\"statusCode\":200,\"message\":\"OK\"}},\"status\":{\"statusCode\":200,\"message\":\"OK\"}}","requestDate":"2025-09-08T10:22:11.174289033+03:30","responseDate":"2025-09-08T10:22:12.921352699+03:30","responseHeaders":{"Content-Type":"application/json;charset=UTF-8"},"cookies":null,"digitalSignature":"","requestId":"1e32083a-a183-42b5-b959-855eac52e56e"}', 1, CAST(N'2025-09-08T06:52:13.4064783' AS DateTime2), NULL)
