INSERT [Log].[VerifyDocLog] ([VerifyDocLogId], [ResponseText], [CreatedAt], [CreatedBy], [DocumentNumber], [VerificationCode], [IsExist], [RequestId], [IsRead], [ReadBy], [ReadDate]) VALUES (9, N'{"isSuccessful":true,"error":0,"errorDescription":"","UsedQuotaStats":{"hourlyUsed":4,"dailyUsed":5,"monthlyUsed":5},"description":"","responseStatusCode":200,"responseText":"{\"result\":{\"data\":{\"RegCases\":[],\"BaseDocuments\":[],\"FollowerDocuments\":[],\"succseed\":true,\"NationalRegisterNo\":\"140332152495000361\",\"DocType\":\"سند وكالت‌نامه\",\"DocType_code\":\"321\",\"HasPermission\":true,\"ExistDoc\":true,\"Desc\":null,\"ScriptoriumName\":\"دفترخانه اسناد رسمي شماره 765 شهر تهران استان تهران\",\"SignGetterTitle\":null,\"SignSubject\":null,\"DocDate\":\"1403/06/07\",\"CaseClasifyNo\":\"94946\",\"ImpotrtantAnnexText\":\"دفترخانه 765 تهران\\nنوع سند: سند وكالت‌نامه\\r\\nتاریخ سند: 1403/06/07\\r\\nشماره سند: 94946\\n--------------------------------------------------\\nوكيل : ايمان دهقاني جغدري\\nموكل : مهندسي بازرگاني سرويس سفيد  با مديريت\\\"آقای سروش جهانديد\\\"\\n--------------------------------------------------\\nموضوع سند: انجام تشريفات گمركي\\n--------------------------------------------------\\nاین وکالتنامه، بلاعزل نیست.\\nوکیل حق توکیل به غیر ندارد.\\nمهلت اعتبار این وکالتنامه تا تاریخ 1404/06/07 بوده است.\\n--------------------------------------------------\\nمتن سند: \\r\\nمورد وكالت : مراجعه به كليه گمركات و بنادر و مناطق آزاد و ويژه تجاري و صنعتي و اقتصادي كشور جهت انجام هرگونه تشريفات گمركي مقرر در قانون و آيين‌نامه اجرائي گمرك از طرف موكل به هر نحو مقتضي و مراجعه به شركتهاي بيمه و كشتيراني و اخذ خسارات احتمالي و انجام كليه امور و تشريفات لازمه و دادن و سپردن و استرداد چكهاي سپرده و سپرده هاي نقدي و دادن رسيد و بيمه نمودن كالاها نزد هريك از شركتهاي بيمه بنام و بنفع موكل يا هر كس ديگر بهر مبلغ و مدت و قيد و شرط و اخذ هرگونه خسارت از بيمه بنحو مقتضي با حق رسيدگي به كليه امور مربوطه در ادارات استاندارد و تحقيقات صنعتي ايران و نمونه گيري براي استاندارد و اخذ هرگونه گواهي و مجوز و سپردن تعهدات لازم و تنظيم و امضاء اظهارنامه بر اسا ماده 192 آيين نامه اجراي قانون امور گمركي و انجام كليه تشريفات بنحويكه در هيچ مورد نيازي به حضور و امضاء مجدد موكل نبوده باشد و كليه اقدام و امضاء وكيل بمنزله اقدام و امضاء موكل نافذ و معتبر و مفاد سند فقط در نفس وكالت مؤثر است.\\rحدود اختيارات : 1- اخذ اسناد خريد و حمل. 2- اخذ قبض انبار و ترخيصيه. 3- تنظيم اظهارنامه. 4- انجام تشريفات گمركي واردات و صادرات و ترانزيت و ورود موقت و مرجوعي / ترخيص كالا. 5- پرداخت حقوق ورودي و عوارض و هزينه هاي گمركي و ماليات هاي متعلقه. 6- اعتراض به تصميمات گمرك و درخواست رد اضافه پرداختي. 7- مراجعه به سازمانهاي ذيربط جهت اخذ مجوزهاي مربوطه. 8- درخواست تعيين تعرفه موضوع ماده 43 قانون امور گمركي. 9- تقاضاي ارجاع پرونده به كميسيون رسيدگي به اختلافات گمركي. 10- اعتراض به آراي كميسيون بدوي و درخواست ارسال پرونده به كميسيون تجديد نظر. 11- حضور در كميسيونهاي بدوي و تجديدنظر رسيدگي به اختلافات گمركي جهت دفاع از پرونده.\\rوكيل فقط حق توكيل به كارمند خود (كارگزار گمركي) را دارد.\",\"DocImage\":null,\"DocImage_Base64\":null,\"ADVOCACYENDDATE\":\"1404/06/07\",\"lstFindPersonInQuery\":[{\"NationalNo\":\"0069310904\",\"Birthdate\":\"1357/06/26\",\"Name\":\"سروش\",\"Family\":\"جهانديد\",\"AgentType\":\"مدير\",\"PersonType\":\"حقیقی\",\"PersonType_code\":\"1\",\"NationalNoMovakel\":\"10102797197\",\"NameMovakel\":\"مهندسي بازرگاني سرويس سفيد\",\"FamilyMovakel\":\"\",\"txtRelation\":\"مهندسي بازرگاني سرويس سفيد  بامديريت سروش جهانديد\",\"RoleType\":\"\",\"Person_RoleType_code\":null},{\"NationalNo\":\"10102797197\",\"Birthdate\":null,\"Name\":\"مهندسي بازرگاني سرويس سفيد\",\"Family\":\"\",\"AgentType\":\"\",\"PersonType\":\"حقوقی\",\"PersonType_code\":\"2\",\"NationalNoMovakel\":\"\",\"NameMovakel\":\"\",\"FamilyMovakel\":\"\",\"txtRelation\":null,\"RoleType\":\"موكل\",\"Person_RoleType_code\":null},{\"NationalNo\":\"3380685410\",\"Birthdate\":\"1374/07/18\",\"Name\":\"ايمان\",\"Family\":\"دهقاني جغدري\",\"AgentType\":\"\",\"PersonType\":\"حقیقی\",\"PersonType_code\":\"1\",\"NationalNoMovakel\":\"\",\"NameMovakel\":\"\",\"FamilyMovakel\":\"\",\"txtRelation\":null,\"RoleType\":\"وكيل\",\"Person_RoleType_code\":null}]},\"status\":{\"statusCode\":200,\"message\":\"OK\"}},\"status\":{\"statusCode\":200,\"message\":\"OK\"}}","requestDate":"2025-09-24T10:53:01.139417404+03:30","responseDate":"2025-09-24T10:53:02.978227098+03:30","responseHeaders":{"Content-Type":"application/json;charset=UTF-8"},"cookies":null,"digitalSignature":"","requestId":"776f36e5-20b3-4466-a56d-38945f9ff163"}', CAST(N'2025-09-24T07:23:01.8763964' AS DateTime2), N'shamel2001', N'140332152495000361', N'153583', NULL, NULL, NULL, NULL, NULL)
